package com.eas.ui.user;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class UserMessagePanel extends UserTablePanel { private final JTextField subject=new JTextField(22); private final JTextArea body=new JTextArea(2,34); public UserMessagePanel(UserSession s){super(s,"Messages to and from Administrator","SELECT m.id,se.full_name sender,re.full_name receiver,m.subject,m.message_body,m.sent_at,m.read_status FROM messages m JOIN users se ON m.sender_id=se.id JOIN users re ON m.receiver_id=re.id WHERE m.sender_id=? OR m.receiver_id=? ORDER BY m.id DESC","SELECT m.id,se.full_name sender,re.full_name receiver,m.subject,m.message_body,m.sent_at,m.read_status FROM messages m JOIN users se ON m.sender_id=se.id JOIN users re ON m.receiver_id=re.id WHERE (m.sender_id=? OR m.receiver_id=?) AND (m.subject LIKE ? OR m.message_body LIKE ? OR se.full_name LIKE ?) ORDER BY m.id DESC",false);JPanel p=new JPanel();p.add(new JLabel("Subject"));p.add(subject);p.add(new JScrollPane(body));JButton send=UITheme.button("SEND TO ADMIN");p.add(send);add(p,BorderLayout.SOUTH);send.addActionListener(e->send());}
 private void send(){try(Connection c=Database.getConnection();PreparedStatement a=c.prepareStatement("SELECT id FROM users WHERE role='ADMIN' AND status='ACTIVE' ORDER BY id LIMIT 1")){try(ResultSet r=a.executeQuery()){if(!r.next())throw new SQLException("No active administrator found.");try(PreparedStatement p=c.prepareStatement("INSERT INTO messages(sender_id,receiver_id,subject,message_body) VALUES(?,?,?,?)")){p.setInt(1,session.getId());p.setInt(2,r.getInt(1));p.setString(3,subject.getText().trim());p.setString(4,body.getText().trim());p.executeUpdate();}}AuditService.log(session.getId(),"MESSAGE","MESSAGES","Sent message to admin.");load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
